def parent_process_alive(parent_pid: int) -> bool:
    """Return True when a parent PID appears alive."""
    if parent_pid <= 0:
        return False
    try:
        os.kill(parent_pid, 0)
        return True
    except ProcessLookupError:
        return False
    except PermissionError:
        return True
    except OSError:
        return False


def should_terminate_stdio_server(
    initial_parent_pid: int,
    current_parent_pid: int,
    elapsed_seconds: float,
    grace_seconds: float,
    parent_alive: bool,
) -> bool:
    """Return True when stdio server should exit due to parent loss."""
    if elapsed_seconds < grace_seconds:
        return False
    if current_parent_pid in (0, 1):
        return True
    if current_parent_pid != initial_parent_pid:
        return True
    if not parent_alive:
        return True
    return False


def start_stdio_orphan_watchdog(
    check_interval: float = 2.0,
    grace_seconds: float = 8.0,
) -> threading.Thread:
    """Start a daemon watchdog that exits orphaned stdio server processes."""
    initial_parent_pid = os.getppid()
    check_interval = max(0.2, float(check_interval))
    grace_seconds = max(0.0, float(grace_seconds))
    started = time.monotonic()

    def monitor() -> None:
        while True:
            elapsed_seconds = time.monotonic() - started
            current_parent_pid = os.getppid()
            parent_alive = parent_process_alive(initial_parent_pid)
            if should_terminate_stdio_server(
                initial_parent_pid=initial_parent_pid,
                current_parent_pid=current_parent_pid,
                elapsed_seconds=elapsed_seconds,
                grace_seconds=grace_seconds,
                parent_alive=parent_alive,
            ):
                log.warning(
                    "Stdio parent process unavailable; exiting orphaned server "
                    f"(initial_ppid={initial_parent_pid}, current_ppid={current_parent_pid})"
                )
                os._exit(0)
            time.sleep(check_interval)

    thread = threading.Thread(
        target=monitor,
        name='nbdev-mcp-stdio-watchdog',
        daemon=True,
    )
    thread.start()
    return thread


def _run_server(
    project: Optional[str] = None,
    transport: Transport = Transport.stdio,
    host: str = "127.0.0.1",
    port: int = 8000,
    path: str = "/mcp",
    verbose: bool = False,
    watch: bool = False,
    watch_interval: float = 2.0,
    watch_cmd: str = "nbdev_export",
) -> None:
    """Internal: run the MCP server."""
    if verbose:
        import logging
        logging.basicConfig(level=logging.DEBUG, format="%(message)s")
        log.setLevel(logging.DEBUG)
        console.print(f"[dim]nbdev-mcp v{__version__}[/]")

    # Set project from env or arg
    proj_path = None
    project = project or os.environ.get("NBDEV_MCP_PROJECT")
    if project:
        try:
            proj_path = resolve_selector(project)
            if verbose:
                console.print(f"[green]✓[/] Project: {proj_path}")
        except Exception as e:
            console.print(f"[red]✗[/] {e}")
            if watch:
                raise typer.Exit(1)

    # Watch mode
    if watch:
        if not proj_path:
            console.print("[red]✗[/] Watch mode requires --project")
            raise typer.Exit(1)
        watch_notebooks(proj_path, interval=watch_interval, on_change=watch_cmd)
        return

    # Enable test recording hooks only when explicitly requested
    recording_flag_raw = os.environ.get("NBDEV_MCP_ENABLE_RECORDING_TOOLS")
    auto_record_raw = os.environ.get("NBDEV_MCP_AUTO_RECORD")
    session_file = os.environ.get("NBDEV_MCP_SESSION_FILE")

    disabled_values = {"", "0", "false", "no", "off"}
    recording_flag_enabled = bool(recording_flag_raw) and recording_flag_raw.strip().lower() not in disabled_values
    auto_record_enabled = bool(auto_record_raw) and auto_record_raw.strip().lower() not in disabled_values

    include_recording_tools = recording_flag_enabled or auto_record_enabled or bool(session_file)

    # Build MCP
    mcp = create_nbdev_mcp(
        include_recording_tools=include_recording_tools,
        sdk_log_level="DEBUG" if verbose else None,
    )

    # Auto-recording for agent tests
    if auto_record_enabled:
        from nbdev_mcp.tests.agent_e2e import start_recording
        start_recording()
        log.info("Auto-recording enabled via NBDEV_MCP_AUTO_RECORD")

    # Register shutdown handler to save session
    if session_file:
        import atexit
        def save_session_on_exit():
            from nbdev_mcp.tests.agent_e2e import stop_recording
            session = stop_recording()
            if session:
                session.save(Path(session_file))
                log.info(f"Session saved to {session_file}")
        atexit.register(save_session_on_exit)

    watchdog_disable_raw = os.environ.get("NBDEV_MCP_DISABLE_STDIO_WATCHDOG", "")
    watchdog_disabled = bool(watchdog_disable_raw) and watchdog_disable_raw.strip().lower() not in disabled_values

    watchdog_interval_raw = os.environ.get("NBDEV_MCP_STDIO_WATCHDOG_INTERVAL", "2.0")
    watchdog_grace_raw = os.environ.get("NBDEV_MCP_STDIO_WATCHDOG_GRACE", "8.0")
    try:
        watchdog_interval = float(watchdog_interval_raw)
    except (TypeError, ValueError):
        watchdog_interval = 2.0
    try:
        watchdog_grace = float(watchdog_grace_raw)
    except (TypeError, ValueError):
        watchdog_grace = 8.0

    match transport:
        case Transport.stdio:
            if not watchdog_disabled:
                start_stdio_orphan_watchdog(
                    check_interval=watchdog_interval,
                    grace_seconds=watchdog_grace,
                )
            mcp.run(transport="stdio")
        case Transport.streamable_http | Transport.http:
            default = (host == "127.0.0.1" and port == 8000 and path == "/mcp")
            if default and transport == Transport.streamable_http:
                mcp.run(transport="streamable-http")
            else:
                try:
                    import uvicorn
                except ImportError:
                    console.print("[red]✗[/] uvicorn required: [dim]pip install uvicorn[/]")
                    raise typer.Exit(1)
                if path != "/mcp":
                    set_http_path_if_supported(path)
                uvicorn.run(mcp.streamable_http_app(), host=host, port=port)


@app.command()
def run(
    project: Annotated[Optional[str], typer.Option(
        "-p", "--project", help="Path or alias for nbdev project."
    )] = None,
    transport: Annotated[Transport, typer.Option(
        "-t", "--transport", help="Transport: stdio, http, streamable-http.",
        envvar="NBDEV_MCP_TRANSPORT"
    )] = Transport.stdio,
    host: Annotated[str, typer.Option(
        "-H", "--host", help="Host for HTTP transport.",
        envvar="NBDEV_MCP_HOST"
    )] = "127.0.0.1",
    port: Annotated[int, typer.Option(
        "-P", "--port", help="Port for HTTP transport.",
        envvar="NBDEV_MCP_PORT"
    )] = 8000,
    path: Annotated[str, typer.Option(
        "--path", help="URL path for HTTP.",
        envvar="NBDEV_MCP_PATH"
    )] = "/mcp",
    verbose: Annotated[bool, typer.Option(
        "-v", "--verbose", help="Debug output."
    )] = False,
    watch: Annotated[bool, typer.Option(
        "-w", "--watch", help="Watch notebooks and auto-export."
    )] = False,
    watch_interval: Annotated[float, typer.Option(
        "--watch-interval", help="Watch polling interval (seconds)."
    )] = 2.0,
    watch_cmd: Annotated[str, typer.Option(
        "--watch-cmd", help="Command on change."
    )] = "nbdev_export",
):
    """Run the MCP server."""
    _run_server(
        project=project, transport=transport, host=host, port=port,
        path=path, verbose=verbose, watch=watch,
        watch_interval=watch_interval, watch_cmd=watch_cmd
    )

